using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: EF Core 9 renamed "Discriminator" to "$type".
        // Existing documents use "Discriminator", so we must preserve it.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: EF Core 9 changed id format from "EntityType|Key" to just "Key".
        // Existing documents use "Blog|1" format, so we must opt back in.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id");
        modelBuilder.Entity<Blog>().UseIdPropertiesForKey(false);

        // Breaking change 3: Cosmos DB provider does not support indexes (sync).
        // HasIndex() threw no error in EF 8, but now throws in EF 9. Removed.
        // (was: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);)
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

