{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF Core 9 Cosmos uses patch-based (partial) updates
        // by default instead of full document replace. Read-then-update patterns
        // still work, but if you need full-document replace semantics, use:
        //   context.Entry(b).State = EntityState.Modified;
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }
}

